 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Popover } from '@patternfly/react-core';
 5	import { HelpIcon } from '@patternfly/react-icons';
 6	
 7	const SelectDiskSourcePopOver: FC = () => {
 8	  const { t } = useKubevirtTranslation();
 9	
10	  return (
11	    <Popover
12	      bodyContent={() => (
13	        <div>
14	          {t(
15	            'Disk Source represents the source for our disk, this can be HTTP, Registry or an existing PVC',
16	          )}
17	        </div>
18	      )}
19	      aria-label={'Help'}
20	    >
21	      <HelpIcon />
22	    </Popover>
23	  );
24	};
25	
26	export default SelectDiskSourcePopOver;

